const xmlData = $input.first().json.data;

const mp3Match = xmlData.match(/url="(https:\/\/[^"]+\.mp3[^"]*)"/);
const titleMatch = xmlData.match(/<title>Mad Money[^<]*<\/title>/);
const dateMatch = xmlData.match(/<pubDate>([^<]+)<\/pubDate>/);

return [{
  json: {
    mp3_url: mp3Match ? mp3Match[1] : null,
    episode_title: titleMatch ? titleMatch[0].replace(/<\/?title>/g, '') : 'Mad Money Episode',
    pub_date: dateMatch ? dateMatch[1] : new Date().toISOString()
  }
}];

const rawUrl = $input.first().json.mp3_url;
const episodeTitle = $input.first().json.episode_title;
const pubDate = $input.first().json.pub_date;

// Fix the &amp; encoding in the URL
const cleanUrl = rawUrl.replace(/&amp;/g, '&');

return [{
  json: {
    mp3_url: cleanUrl,
    episode_title: episodeTitle,
    pub_date: pubDate
  }
}];

const text = $input.first().json.content.parts[0].text;

let html = '';

const lines = text.split('\n');

for (const line of lines) {
  const trimmed = line.trim();

  if (trimmed.startsWith('### ')) {
    const title = trimmed.replace('### ', '');
    html += `<h2 style="color:#ffffff;background:#cc0000;padding:10px 15px;border-radius:6px;margin-top:25px;">${title}</h2>`;
  } else if (trimmed.startsWith('## ')) {
    const title = trimmed.replace('## ', '');
    html += `<h2 style="color:#cc0000;">${title}</h2>`;
  } else if (trimmed === '---') {
    html += '<hr style="border:1px solid #eee;margin:20px 0;">';
  } else if (trimmed.startsWith('* **') || trimmed.startsWith('*   **')) {
    const content = trimmed.replace(/^\*\s+/, '').replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>');
    html += `<div style="background:#f9f9f9;border-left:4px solid #cc0000;padding:12px 15px;margin:10px 0;border-radius:0 6px 6px 0;">${content}</div>`;
  } else if (trimmed.startsWith('* ')) {
    const content = trimmed.replace(/^\*\s+/, '').replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>');
    html += `<div style="padding:6px 15px;margin:4px 0;">&bull; ${content}</div>`;
  } else if (trimmed !== '') {
    const content = trimmed.replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>');
    html += `<p style="margin:6px 0;padding:0 5px;">${content}</p>`;
  }
}

return [{
  json: {
    html_content: html
  }
}];
